const form=document.querySelector('#loanForm'),amount=document.querySelector('#amount'),amountText=document.querySelector('#amountText'),ruleHint=document.querySelector('#ruleHint');
const thaiNumber=value=>{const n=Number(value||0);if(!n)return'';const d=['ศูนย์','หนึ่ง','สอง','สาม','สี่','ห้า','หก','เจ็ด','แปด','เก้า'],p=['','สิบ','ร้อย','พัน','หมื่น','แสน'];const read=g=>{let o='';const s=String(g);for(let i=0;i<s.length;i++){const x=Number(s[i]),pos=s.length-i-1;if(!x)continue;if(pos===1&&x===2)o+='ยี่';else if(pos===1&&x===1)o+='';else if(pos===0&&x===1&&s.length>1)o+='เอ็ด';else o+=d[x];o+=p[pos]||''}return o};let r=Math.floor(n),t='',m=0;if(!r)t=d[0];while(r>0){const g=r%1000000;if(g)t=read(g)+(m?'ล้าน':'')+t;r=Math.floor(r/1000000);m++}return`${t}บาทถ้วน`};
const purposeRules={
'เพื่อการศึกษา อบรม หรือเสนอผลงานวิจัย':{required:['1.1','1.2'],hint:'ต้องแนบ 1.1 และ 1.2 หรือเลือก 1.3 พร้อม 1.6'},
'เพื่อปรับปรุงที่อยู่อาศัย':{required:['1.1','1.5'],hint:'ต้องแนบ 1.1 และ 1.5'},
'เพื่อจัดหาเครื่องมือทางวิชาการ':{required:['1.1','1.4'],hint:'ต้องแนบ 1.1 และ 1.4'},
'เพื่อฉุกเฉิน':{required:['1.1'],hint:'ต้องแนบ 1.1'},
'เพื่อสมนาคุณการเกษียณงานหรือลาออกจากงาน':{required:['1.7'],hint:'ต้องแนบ 1.7'}
};
const updateAttachments=()=>{const selected=form.querySelector('input[name="purpose"]:checked');const rule=selected&&purposeRules[selected.nextElementSibling.textContent.trim()];const boxes=[...form.querySelectorAll('[data-attachment]')];boxes.forEach(box=>{box.closest('.check').classList.remove('required-attachment');});if(!rule){ruleHint.textContent='เลือกวัตถุประสงค์เพื่อแสดงเอกสารแนบที่ต้องใช้';return}ruleHint.textContent=rule.hint;rule.required.forEach(id=>{const box=form.querySelector(`[data-attachment="${id}"]`);if(box){box.checked=true;box.closest('.check').classList.add('required-attachment');}});};
form.querySelectorAll('input[name="purpose"]').forEach(radio=>radio.addEventListener('change',updateAttachments));
amount.addEventListener('input',()=>{if(!amountText.value||amountText.dataset.auto==='true'){amountText.value=thaiNumber(amount.value);amountText.dataset.auto='true'}});amountText.addEventListener('input',()=>amountText.dataset.auto='false');
const exportPdf=async()=>{const options={margin:10,filename:'แบบคำขอกู้ยืมเงินสวัสดิการทางวิชาการ.pdf',image:{type:'jpeg',quality:.96},html2canvas:{scale:2,useCORS:true,backgroundColor:'#ffffff'},jsPDF:{unit:'mm',format:'a4',orientation:'portrait'},pagebreak:{mode:['css','avoid-all']}};if(window.html2pdf){await window.html2pdf().set(options).from(form).save();}else{window.print();}};
document.querySelector('#printButton').addEventListener('click',exportPdf);document.querySelector('#printButtonBottom').addEventListener('click',exportPdf);document.querySelector('#clearButton').addEventListener('click',()=>{if(confirm('ต้องการล้างข้อมูลทั้งหมดหรือไม่?')){form.reset();amountText.dataset.auto='true';updateAttachments();}});form.addEventListener('submit',e=>e.preventDefault());
